//! E2e tests for category: text_processing

use kreuzberg::extract_file_sync;

#[test]
fn test_text_clean_extracted() {
    // Extract and clean text content from document
    let path = r#"json/simple.json"#;
    let mime_type: Option<String> = None;
    let config = Default::default();
    let result = extract_file_sync(&path, mime_type.as_deref(), &config).expect("should succeed");
    assert!(
        result.content.len() >= 5,
        "expected length >= 5, got {}",
        result.content.len()
    );
}

#[test]
fn test_text_normalize_whitespace() {
    // Extract text with whitespace normalization (no consecutive spaces)
    let path = r#"pdf/fake_memo.pdf"#;
    let mime_type: Option<String> = None;
    let config = Default::default();
    let result = extract_file_sync(&path, mime_type.as_deref(), &config).expect("should succeed");
    assert!(
        !format!("{:?}", result.content).contains(r#"  "#),
        "expected NOT to contain: {}",
        r#"  "#
    );
}
